        if (isFirstMessage) {
            // First message: Strictly 15 seconds from send
            if (elapsedSinceStart >= 15000 && aiResponseQueue) {
                displayAIResponse(aiResponseQueue);
                aiResponseQueue = null;
                isFirstMessage = false;
            } else {
                setTimeout(checkAndDisplay, 100);
